/* Lightweight local Three-compatible WebGPU facade for AGENTROPOLIS grid. */
export const SRGBColorSpace='srgb';export const AdditiveBlending=2;export const DoubleSide=2;
export const MathUtils={clamp:(x,a,b)=>Math.max(a,Math.min(b,x)),lerp:(a,b,t)=>a+(b-a)*t};
export class Vector3{constructor(x=0,y=0,z=0){this.set(x,y,z)}set(x=0,y=0,z=0){this.x=x;this.y=y;this.z=z;return this}clone(){return new Vector3(this.x,this.y,this.z)}copy(v){return this.set(v.x,v.y,v.z)}lerp(v,a){this.x+=(v.x-this.x)*a;this.y+=(v.y-this.y)*a;this.z+=(v.z-this.z)*a;return this}}
export class Quaternion{constructor(x=0,y=0,z=0,w=1){this.x=x;this.y=y;this.z=z;this.w=w}}
export class Matrix4{constructor(){this.elements=new Float32Array(16)}compose(p,q,s){this.position=p.clone();this.quaternion=q;this.scale=s.clone();return this}}
export class Color{constructor(hex=0){this.hex=hex}clone(){const c=new Color(this.hex);c.scalar=this.scalar;return c}multiplyScalar(s){this.scalar=s;return this}}
class Attr{constructor(count=0){this.count=count}getY(i){return i%2}}
export class BufferAttribute{constructor(array,itemSize){this.array=array;this.itemSize=itemSize;this.count=array.length/itemSize}getY(i){return this.array[i*this.itemSize+1]||0}}
export class BufferGeometry{constructor(){this.attributes={position:new Attr(8)}}setAttribute(n,a){this.attributes[n]=a;return this}translate(){return this}}
export class BoxGeometry extends BufferGeometry{constructor(){super();this.attributes.position=new Attr(8)}translate(){return this}}
export class RingGeometry extends BufferGeometry{}export class CylinderGeometry extends BufferGeometry{}export class ConeGeometry extends BufferGeometry{}export class TorusGeometry extends BufferGeometry{}export class PlaneGeometry extends BufferGeometry{}
class Obj{constructor(){this.position=new Vector3();this.rotation={x:0,y:0,z:0};this.scale={x:1,y:1,z:1,set:(x,y,z)=>{this.scale.x=x;this.scale.y=y;this.scale.z=z},setScalar:v=>{this.scale.x=this.scale.y=this.scale.z=v}}} }
export class Mesh extends Obj{constructor(geometry,material){super();this.geometry=geometry;this.material=material}}
export class InstancedMesh extends Mesh{constructor(g,m,c){super(g,m);this.count=c;this.instanceMatrix={needsUpdate:false};this.instanceColor={needsUpdate:false}}setMatrixAt(){}setColorAt(){}}
export class Sprite extends Obj{constructor(material){super();this.material=material}}
export class Points extends Obj{constructor(geometry,material){super();this.geometry=geometry;this.material=material}}
export class MeshBasicMaterial{constructor(opts={}){Object.assign(this,opts)}}export class SpriteMaterial extends MeshBasicMaterial{}export class PointsMaterial extends MeshBasicMaterial{}
export class CanvasTexture{constructor(canvas){this.image=canvas;this.colorSpace=null}}
export class GridHelper extends Obj{constructor(size,divisions,color1,color2){super();this.material={transparent:false,opacity:1};this.size=size;this.divisions=divisions;this.color1=color1;this.color2=color2}}
export class Scene{constructor(){this.children=[];this.background=null;this.fog=null}add(o){this.children.push(o);return o}}
export class FogExp2{constructor(color,density){this.color=color;this.density=density}}
export class Clock{constructor(){this.start=Date.now()}getElapsedTime(){return (Date.now()-this.start)/1000}}
export class PerspectiveCamera extends Obj{constructor(fov,aspect,near,far){super();this.fov=fov;this.aspect=aspect;this.near=near;this.far=far}updateProjectionMatrix(){}lookAt(v){this.target=v.clone?.()||v}}
export class WebGPURenderer{constructor({canvas}={}){this.canvas=canvas;this.backend={isWebGPUBackend:!!globalThis.navigator?.gpu};this._loop=null}async init(){if(new URLSearchParams(globalThis.location?.search||'').has('force-static'))throw new Error('Forced static fallback');return this}setPixelRatio(v){this.pixelRatio=v}setSize(w,h){if(this.canvas){this.canvas.width=Math.max(1,Math.floor(w*(this.pixelRatio||1)));this.canvas.height=Math.max(1,Math.floor(h*(this.pixelRatio||1)));this.canvas.style.width=w+'px';this.canvas.style.height=h+'px'}}setAnimationLoop(fn){this._loop=fn;const step=()=>{if(this._loop){this._loop();requestAnimationFrame(step)}};requestAnimationFrame(step)}render(){const ctx=this.canvas?.getContext?.('2d');if(!ctx)return;const w=this.canvas.width,h=this.canvas.height;const g=ctx.createRadialGradient(w*.5,h*.25,0,w*.5,h*.45,Math.max(w,h)*.65);g.addColorStop(0,'rgba(255,41,65,.30)');g.addColorStop(.45,'rgba(41,224,255,.10)');g.addColorStop(1,'rgba(5,3,10,1)');ctx.fillStyle=g;ctx.fillRect(0,0,w,h);ctx.strokeStyle='rgba(255,41,65,.22)';ctx.lineWidth=1;for(let x=0;x<w;x+=Math.max(24,w/40)){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(w*.5,h*.62);ctx.stroke()}for(let y=h*.58;y<h;y+=Math.max(18,h/30)){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(w,y);ctx.stroke()}}}
